/**
 * The Octonionic Compiler (Non-Associative AST)
 * 
 * Traditional Compilers (Associative):
 * (A + B) + C === A + (B + C)
 * The AST optimizer can freely reshape the tree to improve register allocation
 * because the mathematical outcome is identical.
 * 
 * Octonionic Compilers (Non-Associative):
 * (A * B) * C !== A * (B * C)
 * Parentheses are physical boundaries. Grouping operations differently
 * changes the final topological outcome, routing execution without logic gates.
 */

import { fanoMultiply, e, OctonionState, OctonionBasis } from './fano-plane';

export type OctonionicAST = OctonionBasis | OctonionState | [OctonionicAST, OctonionicAST];

/**
 * Reduces a non-associative AST into a single execution state using the Fano Plane.
 */
export function compileOctonionicAST(ast: OctonionicAST): OctonionState {
  // Base case: raw string
  if (typeof ast === 'string') {
    return e(ast as OctonionBasis);
  }

  // Base case: already a state
  if ('basis' in ast && 'sign' in ast) {
    return ast as OctonionState;
  }

  // Recursive reduction of parenthesis boundaries
  if (Array.isArray(ast) && ast.length === 2) {
    const leftNode = compileOctonionicAST(ast[0]);
    const rightNode = compileOctonionicAST(ast[1]);
    
    return fanoMultiply(leftNode, rightNode);
  }

  throw new Error("Invalid AST Node format. Octonionic execution requires strictly binary groupings.");
}

/**
 * Formats a state for terminal output.
 */
export function formatOctonionState(state: OctonionState): string {
  return `${state.sign === 1 ? '+' : '-'}${state.basis}`;
}
